                @foreach ([['list-vms','GET','/projects/{project_uuid}/virtual-machines','vm:read','لیست VMها','پارامترهای اختیاری: search، status و per_page. VMهای deleted به صورت پیش‌فرض حذف می‌شوند.'],['get-vm','GET','/projects/{project_uuid}/virtual-machines/{virtual_machine_uuid}','vm:read','جزئیات VM','رمز عبور در list و detail هرگز برنمی‌گردد. IP، username و SSH command فقط در صورت آماده بودن اتصال ارائه می‌شود.'],['delete-vm','DELETE','/projects/{project_uuid}/virtual-machines/{virtual_machine_uuid}','vm:delete','حذف امن VM','بدنه درخواست باید شامل confirmation برابر display_name دقیق باشد. حذف queue می‌شود و status فورا deleting می‌شود؛ درخواست تکراری idempotent است.']] as [$id,$method,$path,$ability,$title,$description])
